INSERT INTO `eform` (`form_name`, `file_name`, `subject`, `form_date`, `form_time`, `form_creator`, `status`, `form_html`, `patient_independent`, `roleType`, `showLatestFormOnly`, `programNo`, `restrictToProgram`) VALUES
( 'Ontario Lab', '', '2019 Ontario Lab Req v 13', '2023-05-31', '00:00:00', NULL, 1, '<!DOCTYPE>\r\n<html>\r\n<head>\r\n<meta http-equiv=\"Content-Type\" content=\"text/html; charset=UTF-8\">\r\n<meta name=\"description\" content=\"Ontario Outpatient Lab Requisition eForm\" />\r\n<meta name=\"keywords\" content=\"Standard, Lab, Outpatient, Requisition\" />\r\n<meta name=\"robots\" content=\"nofollow\" />\r\n<meta http-equiv=\"author\" content=\"Peter Hutten-Czapski, many others in the community\" />\r\n\r\n<!-- eForm DISCLAIMER: As is: eForms are shared as-is, free of charge on a share-alike basis with absolutely no guarantee or warranty. -->\r\n\r\n<!-- V10 -changed background to 2019/05 -->\r\n<!-- V11 -added tickler setting -->\r\n<!-- V12_Jun2_2022 -added costing per Lifelabs and OHIP schedule  -->\r\n<!-- V13 updated jquery  -->\r\n<title>Lab Requisition Ministry Health Long Term Care</title>\r\n\r\n<style type=\"text/css\" media=\"print\">\r\n .DoNotPrint {\r\n	 display: none;\r\n }\r\n@media print {\r\n  ::-webkit-input-placeholder { /* WebKit browsers */\r\n      color: transparent;\r\n  }\r\n  ::-moz-placeholder { /* Mozilla Firefox 19+ */\r\n      color: transparent;\r\n  }\r\n}\r\n </style>\r\n\r\n<style type=\"text/css\">\r\n input[type=\"text\"], textarea {\r\n	border : 0px;\r\n	background: transparent;\r\n	scrollbar-3dlight-color: transparent;\r\n	scrollbar-arrow-color: transparent;\r\n	scrollbar-base-color: transparent;\r\n	scrollbar-darkshadow-color: transparent;\r\n	scrollbar-face-color: transparent;\r\n	scrollbar-highlight-color: transparent;\r\n	scrollbar-shadow-color: transparent;\r\n	scrollbar-track-color: transparent;\r\n	overflow: hidden;\r\n	font-family:sans-serif;\r\n	font-size:12;\r\n}\r\n.doublesp {\r\n	letter-spacing: 6px;\r\n}\r\n </style>\r\n\r\n<!-- Optional Decision Support Script --> \r\n<script type=\"text/javascript\" src=\"${oscar_image_path}labDecisionSupport.js\"></script>\r\n\r\n<!-- Optional Localised Signature Stamp Script -->\r\n<script src=\'../eform/displayImage.do?imagefile=stamps.js\'></script>\r\n\r\n <!-- main calendar program -->\r\n<script type=\"text/javascript\" src=\"../share/calendar/calendar.js\"></script>\r\n<script type=\"text/javascript\" src=\"../share/calendar/lang/calendar-en.js\"></script>\r\n<script type=\"text/javascript\" src=\"../share/calendar/calendar-setup.js\"></script>\r\n<link rel=\"stylesheet\" type=\"text/css\" media=\"all\" href=\"../share/calendar/calendar.css\" title=\"win2k-cold-1\" />\r\n\r\n<!-- fax control scripts --> <!-- js signature scripts -->\r\n<!-- jQuery for greater functionality -->\r\n<script type=\"text/javascript\" src=\"../library/jquery/jquery-3.6.4.min.js\" ></script>\r\n<script> window.jQuery || document.write(\'<script src=\"../js/jquery-1.12.3.js\">< \\/script>\') </script>\r\n \r\n<script type=\"text/javascript\" src=\"${oscar_javascript_path}eforms/printControl.js\"></script>\r\n<!-- disabled until signature fixed -->\r\n<script type=\"text/javascript\" src=\"${oscar_javascript_path}eforms/faxControl.js\"></script>\r\n\r\n<script type=\"text/javascript\" src=\"${oscar_javascript_path}eforms/signatureControl.jsp\"></script>\r\n\r\n<script type=\"text/javascript\">if (typeof jQuery != \"undefined\" && typeof signatureControl != \"undefined\") {jQuery(document).ready(function() {signatureControl.initialize({eform:true, height:40, width:150, top:870, left:30});});}</script>\r\n\r\n\r\n<!-- xBox scripts -->\r\n<script language=\"javascript\" type=\"text/javascript\">\r\nfunction flip(x){\r\n    if (document.getElementById(x).value == \'\')\r\n        document.getElementById(x).value = \'X\';\r\n    else\r\n        document.getElementById(x).value = \'\';\r\n    }\r\n\r\nfunction key(evt,x) {\r\n    var charCode = (evt.which) ? evt.which : event.keyCode\r\n    // any key press except tab will constitute a value change to the checkbox\r\n    if (charCode != 9){\r\n        flip(x);\r\n        return false;\r\n    }\r\n}\r\n\r\nfunction checkGender(){\r\n     document.getElementById(\'Male\').value = \'\';\r\n     document.getElementById(\'Female\').value = \'\';\r\n     if (document.getElementById(\'PatientGender\').value == \'M\'){\r\n     document.getElementById(\'Male\').value = \'X\';\r\n     }else if (document.getElementById(\'PatientGender\').value == \'F\'){\r\n     document.getElementById(\'Female\').value = \'X\';\r\n    }\r\n }\r\n</script>\r\n\r\n\r\n<!-- scripts to confirm closing of window if it hadn\'t been saved yet -->\r\n<script language=\"javascript\">\r\nvar needToConfirm = false;\r\ndocument.onkeyup=setDirtyFlag;\r\nfunction setDirtyFlag(){\r\n    needToConfirm = true;\r\n}\r\n\r\nfunction releaseDirtyFlag(){\r\n    needToConfirm = false;\r\n}\r\n\r\nwindow.onbeforeunload = confirmExit;\r\n\r\nfunction confirmExit(){\r\n     if (needToConfirm){\r\n         return \"You have attempted to leave this page. If you have made any changes to the fields without clicking the Save button, your changes will be lost. Are you sure you want to exit this page?\";\r\n     }\r\n}\r\n\r\n</script>\r\n\r\n<script type=\"text/javascript\">\r\n\r\nfunction formPrint(){\r\n    //checkProvider();\r\n    window.print();\r\n}\r\n\r\nfunction add(x,test){\r\n    if (document.getElementById(x).value.indexOf(test)==-1){\r\n            document.getElementById(x).value += test\r\n    }\r\n}\r\n\r\nfunction checkProvider(){\r\n    // Check who has opened the eForm\r\n    if ((document.getElementById(\'user_ohip\').value.length<1) || (document.getElementById(\'user_ohip\').value<1000)){\r\n        // the form is being filled by someone on the doctors authority\r\n        if (document.lab.physician.value == \"Falardeau, Marie-Pierre\") {\r\n            document.lab.txtPhysicianNumber.value = \"026688-03\";\r\n            document.lab.physician.value = \"Elgadi, Khaled\";\r\n            document.lab.txtPhysicianAddress.value = \"Temiskaming Hospital\";\r\n            document.lab.txtPhysicianCity.value = \"New Liskeard\";\r\n            document.lab.txtPhysicianPostCode.value = \"P0J 1P0\";\r\n\r\n        } else {\r\n            document.lab.txtPhysicianNumber.value = document.lab.PatientMDsOHIP.value;\r\n            document.lab.physician.value = document.lab.PatientMD.value;\r\n            document.lab.txtPhysicianNumber.value = document.lab.PatientMDsOHIP.value;\r\n        }\r\n    }\r\n    if (document.lab.physician.value != document.lab.PatientMD.value) {\r\n        // add and highlight the option to cc to the doctor on record\r\n        document.getElementById(\'CCMD1\').innerHTML += \"<input type=\'checkbox\' name=\'md1\' id=\'md1\' title=document.lab.PatientMD.value \\\r\n        onClick=\\\"\\\r\n        document.lab.CopyTo.value +=  document.lab.PatientMD.value + \' Dr \'+document.lab.PatientMDsOHIP.value+ \' 95 Meridian Haileybury ON P0J 1K0\';\\\r\n        document.lab.chkCopyToPhysician.value=\'X\';\\\r\n        \\\">Copy to Patients Doctor<br>\";\r\n        hilite(\'CCMD1\');\r\n        document.getElementById(\'md1\').checked=true;\r\n        document.lab.CopyTo.value +=  document.lab.PatientMD.value + \' Dr \'+document.lab.PatientMDsOHIP.value+ \' 95 Meridian Haileybury ON P0J 1K0\';\r\n        document.lab.chkCopyToPhysician.value=\'X\';\r\n    }\r\n\r\n    if (document.lab.physician.value == \"Elgadi, Khaled\") {\r\n        document.lab.txtPhysicianNumber.value = \"026688-03\";\r\n        document.lab.txtPhysicianAddress.value = \"Temiskaming Hospital\";\r\n        document.lab.txtPhysicianCity.value = \"New Liskeard\";\r\n        document.lab.txtPhysicianPostCode.value = \"P0J 1P0\";\r\n    }\r\n}\r\n\r\nfunction clearMe() {\r\n\r\n    for(i=0; i<document.lab.elements.length; i++){\r\n        if (document.lab.elements[i].value == \'X\') { document.lab.elements[i].value =\'\'; }\r\n        if (document.lab.elements[i].type == \'checkbox\') { document.lab.elements[i].checked=false; }\r\n    }\r\n    document.getElementById(\'subject\').value=\'\';\r\n    document.getElementById(\'OtherTests\').value=\'\';\r\n    document.getElementById(\'Instructions\').value=\'\';\r\n    document.getElementById(\'CopyTo\').value=\'\';\r\n    document.getElementById(\'chkOHIP\').value=\'X\';\r\n    checkGender();\r\n    localise();\r\n}\r\n\r\n    var pi=\"INSTRUCTIONS: \";\r\n    var fa=\"Nothing to eat or drink, except for water, for 10 hours prior to the test. \";\r\n    var dr=\"Take your medication AFTER getting your blood drawn. \";\r\n\r\nfunction localise(){\r\n\r\n    if ((document.lab.txtPhysicianPostCode.value==\'P0J 1K0\')||(document.lab.txtPhysicianPostCode.value==\'P0J 1P0\') ){\r\n        checkProvider();\r\n        SignForm();\r\n        //document.lab.CopyTo.value=\'Temiskaming Hospital\\n\';\r\n        //document.lab.chkCopyToPhysician.value=\'X\';\r\n        document.getElementById(\'LOCAL1\').innerHTML =\"<input type=\'checkbox\' name=\'DMclinicCopy\' id=name=\'DMclinicCopy\'\\\r\n        onClick=\\\"\\\r\n        add(\'CopyTo\',\'Temiskaming Diabetes Clinic\\\\nFax 705-647-8766\\\\n\');\\\r\n        document.lab.chkCopyToPhysician.value=\'X\';\\\r\n            \\\">Copy to Diabetes Clinic<br>\\\r\n            <input type=\'checkbox\' name=\'legerCopy\'\\\r\n        onClick=\\\"\\\r\n        add(\'CopyTo\',\'Leger-Nolet, Celine Dr\\\\n Temiskaming Hospital New Liskeard Ontario P0J 1P0\\\\n\');\\\r\n        document.lab.chkCopyToPhysician.value=\'X\';\\\r\n               \\\">Copy to Dr Leger<br>\\\r\n            <input type=\'checkbox\' name=\'bariatricCopy\'\\\r\n        onClick=\\\"\\\r\n        add(\'CopyTo\',\'Bariatric Clinic Health Sciences North,\\\\n41 Ramsey Lake Rd, Sudbury, ON P3E 5J1\\\\nFax 705-671-5635\\\\n\');\\\r\n        document.lab.chkCopyToPhysician.value=\'X\';\\\r\n               \\\">Copy to Bariatric Clinic<br>\\\r\n        <input type=\'checkbox\' name=\'localfax\'\\\r\n        onClick=\\\"\\  document.getElementById(\'otherFaxInput\').value=\'905-795-9891\';\\\r\n               \\\">Toronto fax \\\r\n            <input type=\'checkbox\' name=\'stat\'\\\r\n        onClick=\\\"\\  add(\'Instructions\',\'***STAT*** \');document.getElementById(\'otherFaxInput\').value=\'705-647-1020\';\\\r\n               \\\">STAT\\\r\n            <input type=\'checkbox\' name=\'temH\'\\\r\n        onClick=\\\"\\  ;document.getElementById(\'otherFaxInput\').value=\'705-647-6545\';\\\r\n               \\\">Temiskaming H Lab<br><br>\";\r\n        setTimeout(\'document.getElementById(\"otherFaxInput\").value=\"705-647-1020\"\',1000);\r\n       // document.getElementById(\'ClearButton\').outerHTML += \"<br>STAT fax 705-647-1020\"\r\n    }\r\n\r\n   // if (document.getElementById(\'m$TDP#value\').value.indexOf(\'es\')>0){\r\n   //            add(\'CopyTo\',\'Temiskaming Diabetes Clinic\\nFax 705-647-8766\\n\');\r\n   //    }\r\n}\r\n\r\nfunction Start() {\r\n\r\n    checkGender();\r\n    decisionSupport();\r\n    localise();\r\n\r\n}\r\n\r\n// Localisations\r\n\r\nfunction ChangeImg(img) {\r\n    var ListItemArr =  ImgArray[img].split(\"|\");\r\n    document.getElementById(\'signature\').src = \"../eform/displayImage.do?imagefile=\"+ ListItemArr[1];\r\n}\r\n\r\nfunction SignForm(){\r\n    //sanity check to see if there are signatures loaded\r\n    if (typeof stamps_loaded != \"undefined\") { \r\n        InsertChecks();\r\n        for (i=1; i<ImgArray.length;i++){\r\n            var ListItemArr =  ImgArray[i].split(\"|\");\r\n            var UserName = ListItemArr[0];\r\n            var FileName = ListItemArr[1];\r\n            var InitialsArr = FileName.split(\".\"); \r\n            if (document.getElementById(\'physician\').value.indexOf(UserName)>=0){\r\n                ChangeImg(i);\r\n            }\r\n        }\r\n    } else {\r\n        console.log(\"WARNING: The signature stamps.js file is not found!\");\r\n       return;\r\n    }\r\n}\r\n\r\nfunction InsertChecks(){\r\n    var txt=\"<input type=\'radio\' name=\'imgControl1\' id=\'0\' value=\'0\' onclick=\'ChangeImg(this.value)\' >X\";\r\n    for (i=1; i<ImgArray.length;i++){\r\n        var ListItemArr =  ImgArray[i].split(\"|\");\r\n        var UserName = ListItemArr[0];\r\n        var FileName = ListItemArr[1];\r\n        var InitialsArr = FileName.split(\".\"); \r\n        txt += \"<input type=\'radio\' name=\'imgControl1\' id=\'\"+i+\"\' value=\'\"+i+\"\' onfocus=\'ChangeImg(this.value)\' >\"+InitialsArr[0];\r\n    }\r\n    document.getElementById(\'LOCAL\').innerHTML=txt;\r\n}\r\n\r\n	/****************************\r\n		script to set Tickler reminder for future date (aka loop closer)\r\n	****************************/\r\n	Date.prototype.addDays = function(days) {\r\n		var dat = new Date(this.valueOf());\r\n		dat.setDate(dat.getDate() + days);\r\n		return dat;\r\n	}\r\n\r\n	Date.prototype.addMonths = function(months) {\r\n		var dat = new Date(this.valueOf());\r\n		dat.setMonth(dat.getMonth() + months);\r\n		return dat;\r\n	}\r\n\r\n	function addMonths(months) {\r\n		var d = new Date();\r\n		d = d.addMonths(months);\r\n		var mth = ((d.getMonth()+1)<10)? (\"0\"+(d.getMonth()+1)) : (d.getMonth()+1);\r\n		var day =  d.getDate() > 10 ? d.getDate() : (\"0\" + d.getDate());\r\n		var newD = d.getFullYear() + \"-\" + mth + \"-\" + day;\r\n		document.lab.Tickler_date.value = newD;\r\n	}\r\n\r\n	function addDays(numDays) {\r\n		var d = new Date();\r\n		d = d.addDays(numDays);\r\n		var mth = ((d.getMonth()+1)<10)? (\"0\"+(d.getMonth()+1)) : (d.getMonth()+1);\r\n		var day =  d.getDate() > 10 ? d.getDate() : (\"0\" + d.getDate());\r\n		var newD = d.getFullYear() + \"-\" + mth + \"-\" + day;\r\n		document.lab.Tickler_date.value = newD;\r\n	}\r\n\r\n	ticklerReminder = function() {\r\n		var patient_id = document.getElementById(\'patient_id\').value;\r\n		var user_id = document.getElementById(\'current_user_id\').value;\r\n		var ticklerDate = $( \'#Tickler_date\' ).val();\r\n		var ticklerMsg = \"Review labs. \" + $( \'#Tickler_msg\' ).val();\r\n\r\n		sendTickler(patient_id, ticklerMsg, user_id, ticklerDate);\r\n\r\n		if (ticklerDate == \'\') {\r\n			return(\"ERROR: Tickler reminder date is blank.  Please correct before proceeding.\");\r\n			return;\r\n		}\r\n	} \r\n\r\n	sendTickler = function(demographicNo, message, taskAssignedTo, ticklerDate) {\r\n		var ticklerToSend = {};\r\n\r\n		ticklerToSend.demographicNo = demographicNo;\r\n		ticklerToSend.message = message;\r\n		ticklerToSend.taskAssignedTo = taskAssignedTo;\r\n		ticklerToSend.serviceDate = ticklerDate ;\r\n\r\n	jQuery.ajax( {\r\n		type: \"POST\",\r\n		url:  \'../ws/rs/tickler/add\',\r\n		dataType:\'json\',\r\n		contentType:\'application/json\',\r\n		data: JSON.stringify(ticklerToSend),\r\n		success: processTicklerCallBack\r\n		});\r\n	}\r\n\r\n	processTicklerCallBack = function(data) {\r\n		if(data.success) {\r\n			alert(\"Lab reminder Tickler created and assigned to you.\");\r\n		} else {\r\n			alert(\"ERROR: Tickler failed. Please create tickler manually.\");\r\n		}\r\n	}\r\n\r\n	calculateTicklerDays = function() {\r\n		if(jQuery.trim($(\'#Tickler_date\').val()).length > 0) {\r\n		// calculate future date for Tickler\r\n			var t = new Date(); // today\r\n			var d = new Date(Date.parse(jQuery.trim($(\'#Tickler_date\').val()))); // chosen date or (today + add) - days\r\n			var i = ((Math.floor((d - t)/(1000 * 60 * 60 * 24))) +2); // days forward from today\r\n			d.setDate(d.getDate());\r\n			$( \"#Tickler_date\" ).val(d.toISOString().substring(0,10));\r\n			var NewTickler = document.getElementById(\'Tickler_date\').value;\r\n			alert(\"Once you click Set Tickler button, a reminder will be set for \" + i + \" day(s) from today.  Expect Lab result(s) by \" +  $( \'#Tickler_date\' ).val() + \". Click the Set Tickler button to create reminder now.\");\r\n		}\r\n	}\r\n\r\n</script>\r\n\r\n\r\n<link rel=\"stylesheet\" href=\"${oscar_image_path}autoComplete.css\">\r\n</head>\r\n\r\n<body onload=\"Start();\">\r\n<img id=\'BGImage\' src=\"${oscar_image_path}4422-84v11.png\" style=\"position: absolute; left: 0px; top: 0px; width:750px\">\r\n<form method=\"post\" action=\"\" name=\"lab\" id=\"lab\" >\r\n\r\n\r\n<!-- ----------------------------All textfields/checkboxes/textareas go here...------ -->\r\n<input type=\"hidden\" name=\"today\" id=\"today\" oscarDB=today>\r\n<input type=\"hidden\" name=\"PatientMD\" id=\"PatientMD\" oscarDB=doctor>\r\n<input type=\"hidden\" name=\"PatientMDsOHIP\" id=\"PatientMDsOHIP\" oscarDB=doctor_ohip_no>\r\n<input type=\"hidden\" name=\"PatientAge\" id=\"PatientAge\" oscarDB=age>\r\n<input type=\"hidden\" name=\"curr_user\" id=\"curr_user\" oscarDB=current_user>\r\n<input type=\"hidden\" name=\"user_ohip\" id=\"user_ohip\" oscarDB=current_user_ohip_no>\r\n<input type=\"hidden\" name=\"user_cpsid\" id=\"user_cpsid\" oscarDB=current_user_cpsid>\r\n<input name=\"m$TDP#value\" id=\"m$TDP#value\" type=\"hidden\" oscarDB=m$TDP#value>\r\n\r\n<!-- --------------TESTING FUDGE REMOVE FOR PRODUCTION   ------ \r\n<input type=\"hidden\" name=\"otherFaxInput\" id=\"otherFaxInput\"> --> \r\n\r\n<!-- ---------------------------Extra  Lab Grid Code   ------ -->\r\n<input name=\"TSHvalue\" id=\"TSHvalue\" type=\"hidden\"  oscarDB=m$TSH#value>\r\n<input name=\"TSHdate\" id=\"TSHdate\" type=\"hidden\"  oscarDB=m$TSH#dateObserved>\r\n<input name=\"ACRvalue\" id=\"ACRvalue\" type=\"hidden\"  oscarDB=m$ACR#value>\r\n<input name=\"TCHLvalue\" id=\"TCHLvalue\" type=\"hidden\"  oscarDB=m$TCHL#value>\r\n<input name=\"HDLvalue\" id=\"HDLvalue\" type=\"hidden\"  oscarDB=m$HDL#value>\r\n\r\n<input name=\"BP\" id=\"BP\" type=\"hidden\" oscarDB=m$BP#value>a\r\n<input name=\"dailySmokes\" id=\"dailySmokes\" type=\"hidden\" oscarDB=m$NOSK#value>\r\n<input name=\"smoker\" id=\"smoker\" type=\"hidden\" oscarDB=m$SMK#value>\r\n\r\n<input name=\"m$FRAM#value\" id=\"m$FRAM#value\" type=\"hidden\"  oscarDB=m$FRAM#value>\r\n<input name=\"m$FRAM#dateObserved\" id=\"m$FRAM#dateObserved\" type=\"hidden\"  oscarDB=m$FRAM#dateObserved>\r\n\r\n<input type=\"hidden\" name=\"history\" id=\"history\"  oscarDB=Reminders>\r\n\r\n<input type=\"hidden\" name=\"Meds\" id=\"Meds\"  oscarDB=druglist_generic>\r\n<input type=\"hidden\" name=\"counter\" id = \"counter\" >\r\n<input type=\"hidden\" name=\"history1\" id=\"history1\"  oscarDB=OngoingConcerns>\r\n<input type=\"hidden\" name=\"history2\" id=\"history2\"  oscarDB=Medical_History>\r\n<input type=\"hidden\" name=\"history3\" id=\"history3\"  oscarDB=Other_Medications_History>\r\n<input type=\"hidden\" name=\"history4\" id=\"history4\"  oscarDB=Social_Family_History>\r\n\r\n<input type=\"hidden\" name=\"dxlist\" id=\"dxlist\"  oscarDB=dxregistry>\r\n<input type=\"hidden\" name=\"OHIPlist\" id=\"OHIPlist\"  oscarDB=OHIPdxCode>\r\n\r\n<!-- ------ Hidden inputs needed for Tickler generator (loop closer) -------- -->\r\n<input type=\"hidden\" name=\"patient_id\" id=\"patient_id\" oscarDB=patient_id />\r\n<input type=\"hidden\" name=\"current_user_id\" id=\"current_user_id\" oscarDB=current_user_id />\r\n\r\n<!-- ----------  Main Lab Page --------------------->\r\n\r\n\r\n\r\n<div id=\"LabPage\" style=\"font-family:sans-serif; font-style:normal; font-weight:normal; text-align:left; font-size:12;\">\r\n\r\n<input name=\"physician\" id=\"physician\" type=\"text\" class=\"noborder\" style=\"position:absolute; left:26px; top:86px; width:265px; height:20px; font-size:16px; \" oscarDB=current_user >\r\n\r\n<input name=\"txtPhysicianAddress\" id=\"txtPhysicianAddress\" type=\"text\" class=\"noborder\" style=\"position:absolute; left:26px; top:119px; width:265px; height:15px;\" oscarDB=clinic_addressLine >\r\n<input name=\"txtPhysicianCity\" id=\"txtPhysicianCity\" type=\"text\" class=\"noborder\" style=\"position:absolute; left:26px; top:137px; width:161px; height:15px;\" oscarDB=clinic_city >\r\n<input name=\"txtPhysicianProvince\" id=\"txtPhysicianProvince\" type=\"text\" class=\"noborder\" style=\"position:absolute; left:186px; top:137px; width:101px; height:15px;\" oscarDB=clinic_province >\r\n<input n