width:16px; height:16px; font-weight:bold; text-align:center;\" onmousedown=\"flip(this.id)\" onkeypress=\"javascript:return key(event,this.id); \">\r\n<input name=\"chkMicro_VaginalRectalGroupBStrep\" id=\"chkMicro_VaginalRectalGroupBStrep\" type=\"text\" class=\"noborder\" style=\"position:absolute; left:294px; top:612px; width:16px; height:16px; font-weight:bold; text-align:center;\" onmousedown=\"flip(this.id)\" onkeypress=\"javascript:return key(event,this.id); \">\r\n<input name=\"chkMicro_Chlamydia\" id=\"chkMicro_Chlamydia\" type=\"text\" class=\"noborder\" style=\"position:absolute; left:294px; top:627px; width:16px; height:16px; font-weight:bold; text-align:center;\" onmousedown=\"flip(this.id)\" onkeypress=\"javascript:return key(event,this.id); \">\r\n<input name=\"txtMicro_Chlamydia\" id=\"txtMicro_Chlamydia\" type=\"text\" class=\"noborder\" style=\"position:absolute; left:429px; top:627px; width:79px; height:16px;\" value=\"\">\r\n<input name=\"chkMicro_GC\" id=\"chkMicro_GC\" type=\"text\" class=\"noborder\" style=\"position:absolute; left:294px; top:642px; width:16px; height:16px; font-weight:bold; text-align:center;\" onmousedown=\"flip(this.id)\" onkeypress=\"javascript:return key(event,this.id); \">\r\n<input name=\"txtMicro_GC\" id=\"txtMicro_GC\" type=\"text\" class=\"noborder\" style=\"position:absolute; left:402px; top:642px; width:106px; height:14px;\" value=\"\">\r\n\r\n<input name=\"chkMicro_Sputum\" id=\"chkMicro_Sputum\" type=\"text\" class=\"noborder\" style=\"position:absolute; left:294px; top:657px; width:16px; height:16px; font-weight:bold; text-align:center;\" onmousedown=\"flip(this.id)\" onkeypress=\"javascript:return key(event,this.id); \">\r\n<input name=\"chkMicro_Throat\" id=\"chkMicro_Throat\" type=\"text\" class=\"noborder\" style=\"position:absolute; left:294px; top:673px; width:16px; height:16px; font-weight:bold; text-align:center;\" onmousedown=\"flip(this.id)\" onkeypress=\"javascript:return key(event,this.id); \">\r\n<input name=\"Strep_Link\" id=\"Strep_Link\" type=\"button\" class=\"DoNotPrint\" style=\"position:absolute; left:370px; top:673px; font-size:10px; \" oscarOPEN=\"Strep Throat Risk\" title=\"Modified Centor Pharyngitis Risk Score eForm\" value=\"Strep Throat Risk\">\r\n\r\n<input name=\"chkMicro_Wound\" id=\"chkMicro_Wound\" type=\"text\" class=\"noborder\" style=\"position:absolute; left:294px; top:688px; width:16px; height:16px; font-weight:bold; text-align:center;\" onmousedown=\"flip(this.id)\" onkeypress=\"javascript:return key(event,this.id); \">\r\n<input name=\"txtMicro_Wound\" id=\"txtMicro_Wound\" type=\"text\" class=\"noborder\" style=\"position:absolute; left:416px; top:688px; width:92px; height:14px;\" value=\"\">\r\n\r\n<input name=\"UrineCulture\" id=\"UrineCulture\" type=\"text\" class=\"noborder\" style=\"position:absolute; left:294px; top:704px; width:16px; height:16px; font-weight:bold; text-align:center;\" onmousedown=\"flip(this.id)\" onkeypress=\"javascript:return key(event,this.id); \">\r\n<input name=\"StoolCS\" id=\"StoolCS\" type=\"text\" class=\"noborder\" style=\"position:absolute; left:294px; top:720px; width:16px; height:16px; font-weight:bold; text-align:center;\" onmousedown=\"flip(this.id)\" onkeypress=\"javascript:return key(event,this.id); \">\r\n<input name=\"StoolOP\" id=\"StoolOP\" type=\"text\" class=\"noborder\" style=\"position:absolute; left:294px; top:736px; width:16px; height:16px; font-weight:bold; text-align:center;\" onmousedown=\"flip(this.id)\" onkeypress=\"javascript:return key(event,this.id); \">\r\n<input name=\"chkMicro_Other\" id=\"chkMicro_Other\" type=\"text\" class=\"noborder\" style=\"position:absolute; left:294px; top:752px; width:16px; height:16px; font-weight:bold; text-align:center;\" onmousedown=\"flip(this.id)\" onkeypress=\"javascript:return key(event,this.id); \">\r\n<input name=\"txtMicro_Other\" id=\"txtMicro_Other\" type=\"text\" class=\"noborder\" style=\"position:absolute; left:323px; top:767px; width:174px; height:12px;\" value=\"\">\r\n\r\n<input name=\"txtSpecimenCollectedTime\" id=\"txtSpecimenCollectedTime\" type=\"text\" class=\"noborder\" style=\"position:absolute; left:318px; top:838px; width:74px; height:17px;\" value=\"\">\r\n<input name=\"txtSpecimenCollectedDate\" id=\"txtSpecimenCollectedDate\" type=\"text\" class=\"noborder\" style=\"position:absolute; left:422px; top:838px; width:84px; height:17px;\" value=\"\">\r\n\r\n<input name=\"Hepatitis_Acute\" id=\"Hepatitis_Acute\" type=\"text\" class=\"noborder\" style=\"position:absolute; left:510px; top:417px; width:16px; height:16px; font-weight:bold; text-align:center;\" onmousedown=\"flip(this.id)\" onkeypress=\"javascript:return key(event,this.id); \">\r\n<input name=\"Hepatitis_Chronic\" id=\"Hepatitis_Chronic\" type=\"text\" class=\"noborder\" style=\"position:absolute; left:510px; top:432px; width:16px; height:16px; font-weight:bold; text-align:center;\" onmousedown=\"flip(this.id)\" onkeypress=\"javascript:return key(event,this.id); \">\r\n<input name=\"Hepatitis_ImuneStatus\" id=\"Hepatitis_ImuneStatus\" type=\"text\" class=\"noborder\" style=\"position:absolute; left:510px; top:447px; width:16px; height:16px; font-weight:bold; text-align:center;\" onmousedown=\"flip(this.id)\" onkeypress=\"javascript:return key(event,this.id); \">\r\n<input name=\"HepA\" id=\"HepA\" type=\"text\" class=\"noborder\" style=\"position:absolute; left:571px; top:458px; width:16px; height:16px; font-weight:bold; text-align:center;\" onmousedown=\"flip(this.id)\" onkeypress=\"javascript:return key(event,this.id); \">\r\n<input name=\"HepB\" id=\"HepB\" type=\"text\" class=\"noborder\" style=\"position:absolute; left:571px; top:471px; width:16px; height:16px; font-weight:bold; text-align:center;\" onmousedown=\"flip(this.id)\" onkeypress=\"javascript:return key(event,this.id); \">\r\n<input name=\"HepC\" id=\"HepC\" type=\"text\" class=\"noborder\" style=\"position:absolute; left:571px; top:485px;; width:16px; height:16px; font-weight:bold; text-align:center;\" onmousedown=\"flip(this.id)\" onkeypress=\"javascript:return key(event,this.id); \">\r\n\r\n<input name=\"chkPSA_TotalPSA\" id=\"chkPSA_TotalPSA\" type=\"text\" class=\"noborder\" style=\"position:absolute; left:510px; top:538px; width:16px; height:16px; font-weight:bold; text-align:center;\" onmousedown=\"flip(this.id)\" onkeypress=\"javascript:return key(event,this.id); \">\r\n<input name=\"chkPSA_FreePSA\" id=\"chkPSA_FreePSA\" type=\"text\" class=\"noborder\" style=\"position:absolute; left:603px; top:538px; width:16px; height:16px; font-weight:bold; text-align:center;\" onmousedown=\"flip(this.id)\" onkeypress=\"javascript:return key(event,this.id); \">\r\n<input name=\"PSAvalue\" id=\"PSAvalue\" type=\"text\" class=\"noborder DoNotPrint\" style=\"position:absolute; left:595px; top:555px; width:30px; height:10px; font-size:8px; text-align:left;\" oscarDB=m$PSA#value>\r\n<input name=\"PSAdate\" id=\"PSAdate\" type=\"text\" class=\"noborder DoNotPrint\" style=\"position:absolute; left:630px; top:555px; width:48px; height:10px; font-size:8px; \" oscarDB=m$PSA#dateObserved>\r\n\r\n<input name=\"chkPSA_Insured\" id=\"chkPSA_Insured\" type=\"text\" class=\"noborder\" style=\"position:absolute; left:510px; top:567px; width:16px; height:16px; font-weight:bold; text-align:center;\" onmousedown=\"flip(this.id)\" onkeypress=\"javascript:return key(event,this.id); \">\r\n<input name=\"chkPSA_Uninsured\" id=\"chkPSA_Uninsured\" type=\"text\" class=\"noborder\" style=\"position:absolute; left:510px; top:580px; width:16px; height:16px; font-weight:bold; text-align:center;\" onmousedown=\"flip(this.id)\" onkeypress=\"javascript:return key(event,this.id); \">\r\n\r\n<input name=\"chkVitaminD_Insured\" id=\"chkVitaminD_Insured\" type=\"text\" class=\"noborder\" style=\"position:absolute; left:510px; top:616px; width:16px; height:16px; font-weight:bold; text-align:center;\" onmousedown=\"flip(this.id)\" onkeypress=\"javascript:return key(event,this.id); \">\r\n<input name=\"chkVitaminD_Uninsured\" id=\"chkVitaminD_Uninsured\" type=\"text\" class=\"noborder\" style=\"position:absolute; left:510px; top:653px; width:16px; height:16px; font-weight:bold; text-align:center;\" onmousedown=\"flip(this.id)\" onkeypress=\"javascript:return key(event,this.id); \">\r\n\r\n<textarea name=\"OtherTests\" id=\"OtherTests\" class=\"noborder\" style=\"position:absolute; left:513px; top:686px; width:210px; height:168px;\" ></textarea>\r\n\r\n<input name=\"txtSignatureDate\" id=\"txtSignatureDate\" type=\"text\" class=\"noborder\" style=\"position:absolute; left:196px; top:903px; width:96px; height:21px;\" oscarDB=today>\r\n\r\n<img id=\"signature\" src=\"${oscar_image_path}BNK.png\" width=\"150\" height=\"40\"  style=\"position: absolute; left: 30px; top: 870px;\">\r\n\r\n</div>\r\n\r\n\r\n<!-- ----------- Side Menu Items ------------------------ -->\r\n\r\n<div id=\"LabQuickSelect\" class=\"DoNotPrint\" style=\"position:absolute; left:750px; top:22px; width:400px; background-color:LightYellow; border-style:solid; border-color:black; border-width:1px; font-family: sans-serif; font-size:12;\">\r\n\r\n\r\n<!-------------Base Info----------------------->\r\n<table style=\"width:100%; font-size:10;\">\r\n<!-- Start Column 1 -->\r\n<tr><td style=\"vertical-align:top;\" width=50%>\r\n    <font><u>CONDITIONS:</u></font><br>\r\n    <textarea  name=\"searchbox\" id=\"searchbox\" class=\"noborder\" style=\"font-size:8px; width:190px; height:10px;\" onblur=\"decisionSupport()\" ></textarea><br>\r\n</td><td style=\"vertical-align:top;\" width=50%>\r\n    <font><u>CURRENT MEDS:</u></font><br>\r\n    <textarea  name=\"searchboxRx\" id=\"searchboxRx\" class=\"noborder\" style=\"font-size:8px; width:190px; height:10px;\" onblur=\"decisionSupport()\"></textarea><br>\r\n</td></tr>\r\n</table>\r\n<!-------------Instructions & Copies ----------------------->\r\n    <font><u>INSTRUCTIONS:</u></font><br>\r\n        <input type=\"checkbox\" name=\"PatientCopy\"\r\n    onClick=\"\r\n        add(\'CopyTo\',\'Patient\\n\');\r\n        document.lab.chkCopyToPhysician.value=\'X\';\r\n        \">Copy to Patient\r\n    <input type=\"checkbox\" name=\"FastingInfo\"\r\n    onClick=\"\r\n        add(\'Instructions\',pi);\r\n        add(\'Instructions\',fa);\r\n    \">Fasting Instructions\r\n    <div name=\"LOCAL1\" id=\"LOCAL1\" class=\"temiskaming\">\r\n    </div>\r\n    <div name=\"CCMD1\" id=\"CCMD1\"></div>\r\n\r\n<table style=\"width:100%; font-size:10;\">\r\n<!-- Start Column 1 -->\r\n<tr><td width=50% style=\"vertical-align:top;\">\r\n\r\n<!-------------Therapeutic monitoring---------------->\r\n    <div name=\"DRUG1\" id=\"DRUG1\">\r\n    <font><u>THERAPEUTIC MONITORING</u></font><br>\r\n    <div name=\"DRUG2\" id=\"DRUG2\"> </div>\r\n    </div>\r\n\r\n<!--------ANEMIA-------------------->\r\n    <div name=\"ANEMIA1\" id=\"ANEMIA1\">\r\nANEMIA:<br>\r\n    <input type=\"checkbox\" name=\"Anemia_basic\"\r\n     onClick=\"\r\n        add(\'subject\',\'Anemia \');\r\n        document.lab.CBC.value=\'X\';\r\n        add(\'OtherTests\',\'Ferritin, \');\r\n    \">Anemia Initial<br>\r\n\r\n    <input type=\"checkbox\" name=\"Anemia_advanced\"\r\n     onClick=\"\r\n        add(\'subject\',\'Anemia \');\r\n        document.lab.CBC.value=\'X\';\r\n        document.lab.ALT.value=\'X\';\r\n        document.lab.Albumin.value=\'X\';\r\n        document.lab.Creatinine.value=\'X\';\r\n        document.lab.Bilirubin.value=\'X\';\r\n        document.lab.Urinalysis.value=\'X\';\r\n        add(\'OtherTests\',\'Ferritin, \');\r\n        add(\'OtherTests\',\'HIV, \');\r\n        add(\'OtherTests\',\'LDH, \');\r\n        add(\'OtherTests\',\'SPEP, \');\r\n        add(\'OtherTests\',\'reticulocyte, \');\r\n        add(\'OtherTests\',\'Vit C, \');\r\n    \">Anemia Refractory<br>\r\n    </div>\r\n\r\n\r\n<!-------------CHF---------------->\r\n    <div name=\"CHF1\" id=\"CHF1\">\r\nCHF:<br>\r\n    <input type=\"checkbox\" name=\"CHFBaseline\"\r\n     onClick=\"\r\n        add(\'subject\',\'CHF \');\r\n        document.lab.CBC.value=\'X\';\r\n        document.lab.Glucose.value=\'X\';\r\n        document.lab.GlucoseFasting.value=\'X\';\r\n        add(\'OtherTests\',\'TSH, \');\r\n        document.lab.Sodium.value=\'X\';\r\n        document.lab.Potassium.value=\'X\';\r\n        document.lab.Creatinine.value=\'X\';\r\n        document.lab.ALT.value=\'X\';\r\n        document.lab.Albumin.value=\'X\';\r\n        add(\'OtherTests\',\'EKG, \');\r\n        add(\'Instructions\',pi);\r\n        add(\'Instructions\',fa);\r\n    \">Baseline\r\n\r\n    <input type=\"checkbox\" name=\"CHFFollowUp\"\r\n     onClick=\"\r\n        add(\'subject\',\'CHF \');\r\n        document.lab.Sodium.value=\'X\';\r\n        document.lab.Potassium.value=\'X\';\r\n        document.lab.Creatinine.value=\'X\';\r\n    \">Follow-up<br>\r\n\r\n    <input type=\"checkbox\" name=\"CHFFollowUpStandingQ3months\"\r\n     onClick=\"\r\n        add(\'subject\',\'CHF \');\r\n        add(\'OtherTests\',\'Standing order: Na/K/eGFR Q3monthly for 2 years, \');\r\n    \">Standing Order Q3M<br>\r\n    </div>\r\n\r\n<!----------CKD-------------------->\r\n    <div name=\"CKD3\" id=\"CKD3\">\r\nCKD Stage 3:<br>\r\n    <input type=\"checkbox\" name=\"CKDAnnual\"\r\n     onClick=\"\r\n        add(\'subject\',\'CKD \');\r\n        document.lab.CBC.value=\'X\';\r\n        document.lab.HbA1C.value=\'X\';\r\n        document.lab.ACR.value=\'X\';\r\n        document.lab.Lipids.value=\'X\';\r\n        document.lab.Sodium.value=\'X\';\r\n        document.lab.Potassium.value=\'X\';\r\n        document.lab.Creatinine.value=\'X\';\r\n        add(\'OtherTests\',\'Ca, \');\r\n        document.lab.Albumin.value=\'X\';\r\n        add(\'OtherTests\',\'Iron, Transferrin, \');\r\n        add(\'OtherTests\',\'Phosphorus, iPTH, \');\r\n    \">Annual\r\n\r\n    <input type=\"checkbox\" name=\"CKDQ6months\"\r\n     onClick=\"\r\n        add(\'subject\',\'Chronic Kidney Disease \');\r\n        document.lab.ACR.value=\'X\';\r\n        document.lab.Creatinine.value=\'X\';\r\n        add(\'OtherTests\',\'Standing order: eGFR/ACR Q6monthly for 2 years, \');\r\n    \">eGFR/ACR Q6M<br>\r\n    </div>\r\n<!------DM--------------------->\r\n    <div name=\"DM1\" id=\"DM1\">\r\nDM:<br>\r\n    <input type=\"checkbox\" name=\"DMAnnual\"\r\n     onClick=\"\r\n        add(\'subject\',\'Diabetes \');\r\n        document.lab.HbA1C.value=\'X\';\r\n        document.lab.ACR.value=\'X\';\r\n        document.lab.Glucose.value=\'X\';\r\n        document.lab.GlucoseFasting.value=\'X\';\r\n        document.lab.Sodium.value=\'X\';\r\n        document.lab.Potassium.value=\'X\';\r\n        document.lab.Creatinine.value=\'X\';\r\n        document.lab.Lipids.value=\'X\';\r\n        add(\'Instructions\',pi);\r\n        add(\'Instructions\',fa);\r\n        if (document.getElementById(\'m$TDP#value\').value.indexOf(\'es\')>0){ add(\'CopyTo\',\'Temiskaming Diabetes Clinic\\nFax 705-647-8766\\n\');   };\r\n    \">Annual\r\n\r\n    <input type=\"checkbox\" name=\"DMStandingQ3months\"\r\n    onClick=\"\r\n        add(\'subject\',\'Diabetes \');\r\n        add(\'OtherTests\',\'Standing order: A1C Q3months for 2 years, \');\r\n        if (document.getElementById(\'m$TDP#value\').value.indexOf(\'es\')>0){ add(\'CopyTo\',\'Temiskaming Diabetes Clinic\\nFax 705-647-8766\\n\');   };\r\n    \">A1C Q3M<br>\r\n    </div>\r\n<!--------Dyslipidemia--------------->\r\n    <div name=\"LIPID1\" id=\"LIPID1\">\r\n<a href=\"https://www2.gov.bc.ca/assets/gov/health/practitioner-pro/bc-guidelines/cvd_appendix_c.pdf\" id=\"lipidHeader\" target=\"_blank\" title=\"Guideline for Lipid Testing in Primary Prevention\">DYSLIPIDEMIA:</a><br>\r\n    <input type=\"checkbox\" name=\"CholesterolFBS\"\r\n     onClick=\"\r\n        add(\'subject\',\'Dyslipidemia \');\r\n        document.lab.Glucose.value=\'X\';\r\n        document.lab.GlucoseFasting.value=\'X\';\r\n        document.lab.Lipids.value=\'X\';\r\n        add(\'Instructions\',pi);\r\n        <!-- add(\'Instructions\',fa); -->\r\n    \">Screening\r\n\r\n<!--    <input type=\"checkbox\" name=\"DyslipidemiaOnStatin\"\r\n     onClick=\"\r\n        add(\'subject\',\'Dyslipidemia \');\r\n        add(\'subject\',\'Statin \');\r\n        document.lab.Glucose.value=\'X\';\r\n        document.lab.GlucoseFasting.value=\'X\';\r\n        document.lab.Lipids.value=\'X\';\r\n        document.lab.ALT.value=\'X\';\r\n        add(\'Instructions\',pi);\r\n        add(\'Instructions\',fa);\r\n    \">On Statin<br> -->\r\n    </div>\r\n\r\n\r\n<!--------HEPATITIS-------------------->\r\n    <div id=\"LFT1\" name=\"LFT1\">\r\nHEPATITIS:<br>\r\n  \r\n        <input type=\"checkbox\" name=\"LFT\"\r\n        onClick=\"\r\n            document.lab.ALT.value=\'X\';\r\n            add(\'OtherTests\',\'GGT, \');\r\n            document.lab.ALP.value=\'X\';\r\n            document.lab.Bilirubin.value=\'X\';\r\n            document.lab.Albumin.value=\'X\';\r\n            add(\'OtherTests\',\'Protein, \');\r\n        \">LFTs<br>\r\n</div>\r\n    <input type=\"checkbox\" name=\"AcuteElevatedLFT\"\r\n    onClick=\"\r\n        add(\'subject\',\'Acute Elevated LFT \');\r\n        document.lab.CBC.value=\'X\';\r\n        document.lab.PTINR.value=\'X\';\r\n        document.lab.ALT.value=\'X\';\r\n        add(\'OtherTests\',\'GGT, \');\r\n        document.lab.ALP.value=\'X\';\r\n        document.lab.Bilirubin.value=\'X\';\r\n        document.lab.Albumin.value=\'X\';\r\n        add(\'OtherTests\',\'Protein, \');\r\n        document.lab.Hepatitis_Acute.value=\'X\';\r\n    \">LFT Elevation Acute<br>\r\n\r\n    <input type=\"checkbox\" name=\"ChronicElevatedLFT\"\r\n    onClick=\"\r\n        add(\'subject\',\'Chronic Elevated LFT \');\r\n        document.lab.Glucose.value=\'X\';\r\n        document.lab.GlucoseFasting.value=\'X\';\r\n        document.lab.Lipids.value=\'X\';\r\n        add(\'OtherTests\',\'Ferritin, \');\r\n        document.lab.Hepatitis_Chronic.value=\'X\'\r\n        add(\'OtherTests\',\'ANA, Anti-mitochondrial AB, Ceruloplasmin, Alpha-1 antitrypsin, \');\r\n        add(\'Instructions\',pi);\r\n        add(\'Instructions\',fa);\r\n    \">Chronic Elevated LFTs <br>\r\n\r\n    <input type=\"checkbox\" name=\"ChronicHepatitisBFollow-up\"\r\n    onClick=\"\r\n        add(\'subject\',\'Chronic Hep B \');\r\n        add(\'OtherTests\',\'Standing order: AFP, ALT Q 3 months for 6 months, \');\r\n    \"><a href=\"http://www.hepatology.ca/wp-content/uploads/2012/06/2012HepBGuidelines_CJG.pdf\"\r\n        target=\"_blank\" title=\"Web reference\">Chronic HBV FU</a><br>\r\n\r\n<!--------HTN-------------------->\r\n    <div name=\"HBP1\" id=\"HBP1\">\r\n<a href=\"https://www2.gov.bc.ca/gov/content/health/practitioner-professional-resources/bc-guidelines/hypertension\">HYPERTENSION:</a><br>\r\n    <input type=\"checkbox\" name=\"HypertensionAnnual\"\r\n     onClick=\"\r\n        add(\'subject\',\'Hypertension \');\r\n        document.lab.Glucose.value=\'X\';\r\n        document.lab.Sodium.value=\'X\';\r\n        document.lab.Potassium.value=\'X\';\r\n        document.lab.Creatinine.value=\'X\';\r\n        add(\'Instructions\',pi);\r\n        add(\'Instructions\',fa);\r\n    \">Annual<br>\r\n    </div>\r\n\r\n<!--------Infertility-------------------->\r\n    <div name=\"INF1\" id=\"INF1\">\r\nINFERTILITY:<br>\r\n    <input type=\"checkbox\" name=\"InfertilityFemale\"\r\n    onClick=\"\r\n        add(\'subject\',\'Infertility \');\r\n        document.lab.CBC.value=\'X\';\r\n        document.lab.Rubella.value=\'X\';\r\n        document.lab.PrenatalAntibody.value=\'X\';\r\n        add(\'OtherTests\',\'TSH, \');\r\n        add(\'OtherTests\',\'HBsAg, \');\r\n        add(\'OtherTests\',\'HIV, \');\r\n        add(\'OtherTests\',\'Cycle day 3 FSH, Estradiol, Prolactin, Hep C, VDRL, \');\r\n        add(\'Instructions\',pi);\r\n        add(\'Instructions\',\'Do blood work in the 3rd day of your cycle/period. \');\r\n        \">Infertility Female\r\n\r\n    <input type=\"checkbox\" name=\"InfertilityMale\"\r\n    onClick=\"\r\n        add(\'subject\',\'Infertility \');\r\n        document.lab.CBC.value=\'X\';\r\n        add(\'OtherTests\',\'HIV, \');\r\n        add(\'OtherTests\',\'TSH, \');\r\n        add(\'OtherTests\',\'Semenalysis, \');\r\n           \">Male<br>\r\n    <input type=\"checkbox\" name=\"AbnSA\"\r\n    onClick=\"\r\n        add(\'subject\',\'Infertility \');\r\n        document.lab.CBC.value=\'X\';\r\n        add(\'OtherTests\',\'HIV, \');\r\n        add(\'OtherTests\',\'TSH, \');\r\n        add(\'OtherTests\',\'FSH, LH, Prolactin, Testosterone, Karyotype, \');\r\n           \">Abn Semen Analysis<br>\r\n\r\n    </div>\r\n\r\n\r\n<!--------Prenatal-------------------->\r\n    <div name=\"PN1\" id=\"PN1\">\r\nPRENATAL:<br>\r\n        <input type=\"checkbox\" name=\"Prenatal\"\r\n    onClick=\"\r\n        add(\'subject\',\'Pregnant ?asymptomatic bacteriuria \');\r\n        document.lab.CBC.value=\'X\';\r\n        document.lab.UrineCulture.value=\'X\';\r\n        document.lab.PrenatalAntibody.value=\'X\';\r\n        document.lab.chkMicro_Chlamydia.value=\'X\';\r\n        document.lab.txtMicro_Chlamydia.value=\'urine\';\r\n        document.lab.chkMicro_GC.value=\'X\';\r\n        document.lab.txtMicro_GC.value=\'urine\';\r\n        document.lab.Rubella.value=\'X\';\r\n        add(\'OtherTests\',\'HBsAg, \');\r\n        add(\'OtherTests\',\'anti-HCV, \');\r\n        add(\'OtherTests\',\'HIV, \');\r\n        add(\'OtherTests\',\'Syphilis screen, \');\r\n    \">Prenatal:First visit labs<br>\r\n\r\n    <input type=\"checkbox\" name=\"Prenatal2\"\r\n    onClick=\"\r\n        add(\'OtherTests\',\'TSH, \');\r\n        add(\'OtherTests\',\'anti-HCV, \');\r\n        add(\'OtherTests\',\'Varicella Titre, \');\r\n        add(\'OtherTests\',\'CMV, \');\r\n        add(\'OtherTests\',\'Parovirus, \');\r\n        add(\'OtherTests\',\'Toxoplasmosis, \');\r\n        add(\'OtherTests\',\'Ferritin, \');\r\n        add(\'OtherTests\',\'B12, \');\r\n    \">Prenatal:Discretionary labs<br>\r\n\r\n    <input type=\"checkbox\" name=\"PET\"\r\n    onClick=\"\r\n        add(\'subject\',\'Gestational-HTN \');\r\n        document.lab.CBC.value=\'X\';\r\n        document.lab.Sodium.value=\'X\';\r\n        document.lab.Potassium.value=\'X\';\r\n        document.lab.Creatinine.value=\'X\';\r\n        add(\'OtherTests\',\'Ca, \');\r\n        document.lab.ALT.value=\'X\';\r\n        add(\'OtherTests\',\'GGT, \');\r\n        document.lab.Glucose.value=\'X\';\r\n        document.lab.GlucoseRandom.value=\'X\';\r\n        document.lab.Bilirubin.value=\'X\';\r\n        document.lab.Albumin.value=\'X\';\r\n        document.lab.PTINR.value=\'X\';\r\n        add(\'OtherTests\',\'BUN, HCO3-,Mg2+, Uric Acid, LDH, Fibrinogen,\\nRandom Urine for Protein:Creatinine Ratio,(NOT ACR)\\n\');\r\n    \">Prenatal:Gestational HTN<br>\r\n<!-- Prenatal Public Health - use other eForm -->\r\n    <input name=\"Pub_H_link\" id=\"Pub_H_link\" value=\"Pub Health\" type=\"button\" style=\"font-size:10px;\" oscarOpen=\"Prenatal HIV VDRL Rubella\" title=\"Ontario Public Health Screening for HIV VDRL Rubella\"><br>\r\n<!-- PGS - use other eForm -->\r\n    <input id=\"PGS_link\" name=\"PGS_link\" value=\"NYG Prenatal\" type=\"button\" style=\"font-size:10px;\" oscarOpen=\"PN Downs Screening NY\" title=\"Prenatal Genetic Screening, aka eFTS\">\r\n<!-- NIPT - use other eForm -->\r\n    <input name=\"NIPT_link\" id=\"NIPT_link\" value=\"Panorama\" type=\"button\" style=\"font-size:10px;\" oscarOpen=\"Panorama\" title=\"Private Panorama NIPT or Trisomy 21 18 or 13 with criterea\"><br>\r\n\r\n    </div>\r\n<!-- Start Column 2 -->\r\n</td><td width=50% style=\"vertical-align:top;\">\r\n<!-------Other-------------------->\r\n    <u>OTHERS:</u><br>\r\n    <input type=\"checkbox\" name=\"Autoimmune\" title=\"RF ANA are done once, serial values generally not useful\"\r\n    onClick=\"\r\n        add(\'subject\',\'?autoimmune \');\r\n        add(\'OtherTests\',\'ANA, \');\r\n        add(\'OtherTests\',\'RF, \');\r\n        add(\'OtherTests\',\'CRP, \');\r\n        document.lab.CBC.value=\'X\';\r\n    \">Autoimmune\r\nANA, \r\nRF<br>\r\n    <div name=\"CBC1\" id=\"CBC1\">\r\n        <input type=\"checkbox\" name=\"CompleteBloodCount\"\r\n        onClick=\"\r\n            document.lab.CBC.value=\'X\';\r\n        \">CBC<br>\r\n    </div>\r\n    <input type=\"checkbox\" name=\"Celiac\" title=\"Done once, generally serial values to TTG are not useful\"\r\n    onClick=\"\r\n        add(\'subject\',\'?Celiac disease \');\r\n        add(\'OtherTests\',\'Anti-TTG IgA for celiac disease and Total IgA, \');\r\n    \">Celiac disease </font><br>\r\n    <input type=\"checkbox\" name=\"BAR\"\r\n    onClick=\"\r\n        add(\'subject\',\'Bariatric \');\r\n        document.lab.CBC.value=\'X\';\r\n        document.lab.Sodium.value=\'X\';\r\n        document.lab.Potassium.value=\'X\';\r\n        document.lab.Creatinine.value=\'X\';\r\n        document.lab.ALT.value=\'X\';\r\n        document.lab.ACR.value=\'X\';\r\n        document.lab.Glucose.value=\'X\';\r\n        document.lab.GlucoseFasting.value=\'X\';\r\n        document.lab.HbA1C.value=\'X\';\r\n        document.lab.Lipids.value=\'X\';\r\n        document.lab.Bilirubin.value=\'X\';\r\n        document.lab.Albumin.value=\'X\';\r\n        document.lab.chkVitaminD_Insured.value=\'X\';\r\n        add(\'OtherTests\',\'Urea, Ca, Phosphate,\\nAlk Phos, PTH, Zinc, Copper,\\nIron, B12, Ferritin,\\nVit A, B1(Thiamine), TSH,\\n H Pylori (PHL req)\');\r\n    \">Bariatric\r\n    <input type=\"checkbox\" name=\"BARA\"\r\n    onClick=\"\r\n        add(\'subject\',\'Bariatric annual \');\r\n        document.lab.CBC.value=\'X\';\r\n        document.lab.Sodium.value=\'X\';\r\n        document.lab.Potassium.value=\'X\';\r\n        document.lab.Creatinine.value=\'X\';\r\n        document.lab.ALT.value=\'X\';\r\n        document.lab.ACR.value=\'X\';\r\n        document.lab.Glucose.value=\'X\';\r\n        document.lab.GlucoseFasting.value=\'X\';\r\n        document.lab.HbA1C.value=\'X\';\r\n        document.lab.Lipids.value=\'X\';\r\n        document.lab.Bilirubin.value=\'X\';\r\n        document.lab.Albumin.value=\'X\';\r\n        document.lab.chkVitaminD_Insured.value=\'X\';\r\n        add(\'OtherTests\',\'Urea, Ca, Phosphate,\\nAlk Phos, Bilirubin,PTH, Zinc\\nB12, RBC Folate, Ferritin, Vit A\');\r\n    \">annual\r\n<br>\r\n    <input type=\"checkbox\" name=\"Dementia\"\r\n     onClick=\"\r\n        add(\'subject\',\'Memory issues \');\r\n        document.lab.CBC.value=\'X\';\r\n        document.lab.Glucose.value=\'X\';\r\n        document.lab.GlucoseFasting.value=\'X\';\r\n        add(\'OtherTests\',\'TSH, \');\r\n        document.lab.Sodium.value=\'X\';\r\n        document.lab.Potassium.value=\'X\';\r\n        add(\'OtherTests\',\'Ca, \');\r\n        document.lab.Creatinine.value=\'X\';\r\n        document.lab.ALT.value=\'X\';\r\n        add(\'OtherTests\',\'GGT, \');\r\n         document.lab.UrineCulture.value=\'X\';\r\n        add(\'OtherTests\',\'B12, \');\r\n        add(\'Instructions\',pi);\r\n        add(\'Instructions\',fa);\r\n    \">Dementia<br>\r\n\r\n    <input type=\"checkbox\" name=\"Eatingdisorderworkup\"\r\n     onClick=\"\r\n        add(\'subject\',\'Eating disorder \');\r\n        document.lab.CBC.value=\'X\';\r\n        document.lab.Glucose.value=\'X\';\r\n        document.lab.GlucoseFasting.value=\'X\';\r\n        document.lab.Lipids.value=\'X\';\r\n        add(\'OtherTests\',\'TSH, \');\r\n        add(\'OtherTests\',\'Ferritin, \');\r\n        document.lab.UrineCulture.value=\'X\';\r\n        document.lab.Sodium.value=\'X\';\r\n        document.lab.Potassium.value=\'X\';\r\n        document.lab.Creatinine.value=\'X\';\r\n        add(\'OtherTests\',\'Ca, \');\r\n        document.lab.ALT.value=\'X\';\r\n        add(\'OtherTests\',\'GGT, \');\r\n        document.lab.ALP.value=\'X\';\r\n        document.lab.Bilirubin.value=\'X\';\r\n        document.lab.Albumin.value=\'X\';\r\n        add(\'OtherTests\',\'Protein, \');\r\n        add(\'OtherTests\',\'EKG, \');\r\n        add(\'OtherTests\',\'Mg, PO4, \');\r\n        add(\'Instructions\',pi);\r\n        add(\'Instructions\',fa);\r\n    \">Eating disorder workup<br>\r\n\r\n    <input type=\"checkbox\" name=\"Fatigue\"\r\n     onClick=\"\r\n        add(\'subject\',\'Fatigue \');\r\n        document.lab.CBC.value=\'X\';\r\n        document.lab.Glucose.value=\'X\';\r\n        document.lab.GlucoseFasting.value=\'X\';\r\n        add(\'OtherTests\',\'TSH, \');\r\n        add(\'OtherTests\',\'Ferritin, \');\r\n        document.lab.Sodium.value=\'X\';\r\n        document.lab.Potassium.value=\'X\';\r\n        document.lab.Creatinine.value=\'X\';\r\n        document.lab.ALT.value=\'X\';\r\n        add(\'OtherTests\',\'GGT, \');\r\n        add(\'Instructions\',pi);\r\n        add(\'Instructions\',fa);\r\n    \">Fatigue<br>\r\n\r\n    <input type=\"checkbox\" name=\"GynCa\"\r\n    onClick=\"\r\n        add(\'subject\',\'Gynae Ca f/u, \');\r\n        add(\'OtherTests\',\'CA125, CEA, CA19-9, CA15-3, \');\r\n    \">Gyne Cancer<br>\r\n\r\n    <div id=\"INR1\" name=\"INR1\">\r\n        <input type=\"checkbox\" name=\"INRStanding\"\r\n        onClick=\"\r\n            add(\'subject\',\'Warfarin \');\r\n            add(\'OtherTests\',\'Standing Order: INR PRN for 6 months. \');\r\n        \">INR - Standing Order<br>\r\n    </div>\r\n\r\n\r\n    <input type=\"checkbox\" name=\"FemaleOsteoporosis\"\r\n    onClick=\"\r\n        add(\'subject\',\'Osteoporosis \');\r\n        document.lab.CBC.value=\'X\';\r\n            add(\'OtherTests\',\'TSH, \');\r\n        add(\'OtherTests\',\'Ca, \');\r\n        document.lab.ALP.value=\'X\';\r\n        add(\'Instructions\',pi);\r\n        add(\'OtherTests\',\'Phosphate, serum protein electrophoresis, \');\r\n        \">Osteoporosis Female\r\n\r\n    <input type=\"checkbox\" name=\"MaleOsteoporosis\"\r\n    onClick=\"\r\n        add(\'subject\',\'Osteoporosis \');\r\n            add(\'OtherTests\',\'TSH, \');\r\n        document.lab.CBC.value=\'X\';\r\n        document.lab.Sodium.value=\'X\';\r\n        document.lab.Potassium.value=\'X\';\r\n        document.lab.Creatinine.value=\'X\';\r\n        add(\'OtherTests\',\'Ca, \');\r\n        document.lab.ALP.value=\'X\';\r\n        document.lab.chkVitaminD_Insured.value=\'X\';\r\n        add(\'OtherTests\',\'Phosphate, total and bio-available testosterone, iPTH, urinary calcium excretion, \');\r\n        add(\'Instructions\',pi);\r\n        add(\'Instructions\',\'Do blood work in the morning, before 10:00 a.m. \');\r\n        \">Male<br>\r\n\r\n    <input type=\"checkbox\" name=\"PCOSworkup\"\r\n     onClick=\"\r\n        add(\'subject\',\'?PCOS \');\r\n        document.lab.CBC.value=\'X\';\r\n        document.lab.Glucose.value=\'X\';\r\n        document.lab.GlucoseFasting.value=\'X\';\r\n        add(\'OtherTests\',\'TSH, \');\r\n        add(\'OtherTests\',\'FSH, \');\r\n        add(\'OtherTests\',\'LH, \');\r\n        add(\'OtherTests\',\'Prolactin, \');\r\n        add(\'OtherTests\',\'Total testosterone, \');\r\n        add(\'OtherTests\',\'DHEAS, \');\r\n    \">PCOS workup<br>\r\n\r\n<!-- Recurrent Pregnancy Loss/RPL -->\r\n    <input type=\"checkbox\" name=\"Recurrent_Pregnancy_Loss\"\r\n    onClick=\"\r\n        document.lab.Sodium.value=\'X\';\r\n        document.lab.Potassium.value=\'X\';\r\n        document.lab.Creatinine.value=\'X\';\r\n        document.lab.PrenatalAntibody=\'X\';\r\n        add(\'OtherTests\',\'Cycle day 3 FSH, \');\r\n        add(\'OtherTests\',\'LH, \');\r\n        add(\'OtherTests\',\'Prolactin, \');\r\n        add(\'OtherTests\',\'Testosterone, \');\r\n        add(\'OtherTests\',\'DHEAS, \');\r\n        add(\'OtherTests\',\'Estradiol, \');\r\n        add(\'OtherTests\',\'Rubella, \');\r\n        add(\'OtherTests\',\'anti-HCV, \');\r\n        add(\'OtherTests\',\'Syphillis screen, \');\r\n        add(\'OtherTests\',\'Lupus Anticoagulant/DRVVT, \');\r\n        add(\'OtherTests\',\'Cardiolipin Ab, \');\r\n        add(\'OtherTests\',\'Beta 2 Glycoprotein 1, \');\r\n        \">Recurrent Pregnancy Loss<br>\r\n\r\n    <div id=\"LYTES1\" name=\"LYTES1\">\r\n        <input type=\"checkbox\" name=\"RenalFunction\"\r\n        onClick=\"\r\n            document.lab.Sodium.value=\'X\';\r\n            document.lab.Potassium.value=\'X\';\r\n            document.lab.Creatinine.value=\'X\';\r\n        \">Renal Function<br>\r\n    </div>\r\n    <input type=\"checkbox\" name=\"Stool\"\r\n    onClick=\"\r\n        add(\'subject\',\'Diarrhea,\');\r\n        document.lab.StoolCS.value=\'X\';\r\n        document.lab.StoolOP.value=\'X\';\r\n    \">\r\n    <a href=\"https://www2.gov.bc.ca/gov/content/health/practitioner-professional-resources/bc-guidelines/infectious-diarrhea\" title=\"Guideline for ordering Stool Specimens\">Stool O+P,C+S</a><br>\r\n    <input type=\"checkbox\" name=\"RLS\"\r\n    onClick=\"\r\n       document.lab.CBC.value=\'X\';\r\n       document.lab.Creatinine.value=\'X\';\r\n       add(\'OtherTests\',\'B12, Folate, TSH, Ferritin\\n\');\r\n        \">Restless Leg<br>\r\n    <input type=\"checkbox\" name=\"Thrombosisscreen\"\r\n    onClick=\"\r\n        add(\'subject\',\'Thrombosis-Screen \');\r\n        document.lab.CBC.value=\'X\';\r\n        document.lab.PTINR.value=\'X\';\r\n        add(\'OtherTests\',\'TSH, \');\r\n        add(\'OtherTests\',\'Factor 5 Leiden, Protein C, Protein S, Antithrombin 3, DRVVT, \');\r\n    \">Thrombosis screen<br>\r\n\r\n    <div name=\"THYROID1\" id=\"THYROID1\">\r\n        <input type=\"checkbox\" name=\"TSHStandingorder\"\r\n        onClick=\"\r\n            add(\'subject\',\'Thyroid screen \');            \r\n                add(\'OtherTests\',\'TSH, \');\r\n        \"><a href=\"https://www2.gov.bc.ca/gov/content/health/practitioner-professional-resources/bc-guidelines/thyroid-testing\" title=\"Guideline for ordering Thyroid Tests\">Thyroid screen</a><br>\r\n\r\n        <input type=\"checkbox\" name=\"TSHStandingorder\"\r\n        onClick=\"\r\n            add(\'subject\',\'Hypothyroidism \');            \r\n                add(\'OtherTests\',\'Standing Order: TSH annually for 2 years, \');\r\n        \">TSH\r\n Standing Order<br>\r\n    </div>\r\n    <input type=\"checkbox\" name=\"UrineC&S\"\r\n    onClick=\"\r\n        add(\'subject\',\'UTI \');            \r\n        document.lab.UrineCulture.value=\'X\';\r\n        \">Urine C&S<br>\r\n\r\n    <input type=\"checkbox\" name=\"VaginitisInitial\"\r\n    onClick=\"\r\n        add(\'subject\',\'Vaginal discharge \');\r\n        document.lab.chkMicro_Vaginal.value=\'X\';\r\n    \">Vaginitis\r\n    <br>\r\n\r\n</td>\r\n</tr>\r\n</table>\r\n<input name=\"subject2\" class=\"labBox\" size=\"70\" type=\"text\">\r\n		Approximate cost of todays lab work: &nbsp;&nbsp; <b>$</b>\r\n		<input name=\"Costs\" id= \"Costs\" type=\"text\" style=\"width:40px; text-align:center; font-weight:bold; font-size:14px; background:transparent;\" class=\"noborder labBox\"><br>\r\n&nbsp;<input value=\"Clear\" name=\"ClearButton\" id=\"ClearButton\" type=\"button\" onclick=\"clearMe();\">\r\n<hr>\r\n    \r\n<!-- Tickler Reminders (aka loop closer) -->\r\n<div name=\"SetTickler\" id=\"SetTickler\" style=\"font-size:14px;\" class=\"DoNotPrint\">\r\n	<u><span style=\"font-size:12px;\">Choose Tickler reminder date</span></u>\r\n&nbsp;<input name=\"ResetTickler\" id=\"ResetTickler\" type=\"button\" style=\"font-size:10px; color:red;\" onclick=\"document.getElementById(\'Tickler_date\').value = \'\'; document.getElementById(\'Four_weeks\').checked = false; document.getElementById(\'Six_weeks\').checked = false; addDays(0);\" value=\"Reset\"><br>\r\n	\r\n	<input name=\"Tickler_date\" id=\"Tickler_date\" type=\"text\" class=\"noborder\" style=\"width:95px; font-size:14px; text-align:center; background:transparent;\" onblur=\"calculateTicklerDays();\">\r\n\r\n	<input name=\"Four_weeks\" id=\"Four_weeks\" type=\"checkbox\" \r\n		onclick=\"\r\n			document.getElementById(\'Six_weeks\').checked = false;\r\n			addDays(28); // need to add extra day for proper calculation\r\n			calculateTicklerDays();\">4 weeks\r\n	<input name=\"Six_weeks\" id=\"Six_weeks\" type=\"checkbox\" \r\n		onclick=\"\r\n			document.getElementById(\'Four_weeks\').checked = false;\r\n			addDays(42); // need to add extra day for proper calculation\r\n			calculateTicklerDays();\">6 weeks<br>\r\n	<input name=\"Tickler_msg\" id=\"Tickler_msg\" type=\"text\" class=\"noborder\" style=\"font-size:14px; background:transparent; width: 250px;\" placeholder=\"Optional Tickler msg here\"><br>\r\n	&nbsp;<input value=\"Set Tickler\" name=\"Tickler\" id=\"Tickler\" type=\"button\" class=\"link\"  title=\"Set tickler reminder for chosen future date\" onclick=\"ticklerReminder();\"> &nbsp; &nbsp; \r\n</div>\r\n\r\n</div>\r\n\r\n<!--  ----------- Signature, either a stamp or canvas object, this contains the value of the canvas object ----------------------- -->\r\n\r\n\r\n<div id=\"signatureDisplay\" ></div><input type=\"hidden\" name=\"signatureValue\" id=\"signatureValue\" value=\"\" ></input>\r\n\r\n<!--  ----------- Fax Signature Printing and Saving Controls ----------------------- -->\r\n\r\n<div class=\"DoNotPrint\" id=\"BottomButtons\" style=\"position: absolute; top:971px; left:10px;\">\r\n\r\n<input name=\"subject\" id=\"subject\"  type=\"text\">\r\n    <table><tr id=sig>\r\n    <td> <div id=\"signatureInput\">&nbsp;</div></td>\r\n    <td> <div id=\"faxControl\">&nbsp;</div></td>\r\n    </tr></table>\r\n    <table><tr><td>\r\n            <input value=\"Submit\" name=\"SubmitButton\" id=\"SubmitButton\" type=\"submit\" onclick=\"releaseDirtyFlag();\">\r\n            <input value=\"Reset\" name=\"ResetButton\" id=\"ResetButton\" type=\"reset\">\r\n            <input value=\"Only Print\" name=\"PrintButton\" id=\"PrintButton\" type=\"button\" onclick=\"formPrint();\">\r\n            <input value=\"Print & Submit\" name=\"PrintSubmitButton\" id=\"PrintSubmitButton\" type=\"button\" onclick=\"formPrint();releaseDirtyFlag();alert(\'Click OK to Finish Submitting\');SubmitButton.click();\"> <br>\r\n\r\n\r\n     </td></tr></table>\r\n        <div id=\"LOCAL\" name=\"LOCAL\">    </div>\r\n\r\n </div>\r\n </form>\r\n\r\n<script type=\"text/javascript\" src=\"${oscar_image_path}searchProfessionalSpecialist.js\"></script>\r\n</body>\r\n<script type=\"text/javascript\">\r\n	Calendar.setup({inputField:\"Tickler_date\", ifFormat:\"%Y-%m-%d\", showsTime:false, button:\"Tickler_date\"});\r\n\r\nfunction StartAddIfMissingTitle(x,content) {\r\n			document.getElementById(x).title = content\r\n		}\r\n	$(\"#GlucoseFasting\").attr(\'title\', \'Cost: $1.28\');\r\n	$(\"#GlucoseRandom\").attr(\'title\', \'Cost: $1.28\');\r\n	$(\"#HbA1C\").attr(\'title\', \'Cost: $7.25\');\r\n	$(\"#Creatinine\").attr(\'title\', \'Cost: $1.28\');\r\n	$(\"#UricAcid\").attr(\'title\', \'Cost: $1.16\');\r\n	$(\"#Sodium\").attr(\'title\', \'Cost: $1.16\');\r\n	$(\"#Potassium\").attr(\'title\', \'Cost: $1.16\');\r\n	$(\"#ALT\").attr(\'title\', \'Cost: $1.28\');\r\n	$(\"#ALP\").attr(\'title\', \'Cost: $1,57\');\r\n	$(\"#Bilirubin\").attr(\'title\', \'Cost: $1.55\');\r\n	$(\"#Albumin\").attr(\'title\', \'Cost: $1.55\');\r\n	$(\"#Lipids\").attr(\'title\', \'Cost: $21,31\');\r\n	$(\"#ACR\").attr(\'title\', \'Cost: $11,41\');\r\n	$(\"#Urinalysis\").attr(\'title\', \'Cost: $2.15\');\r\n	$(\"#NeonatalBilirubin\").attr(\'title\', \'Cost: $1.55\');\r\n \r\n    $(\"#CBC\").attr(\'title\', \'Cost: $3.98\');\r\n	$(\"#PregnancyTestUrine\").attr(\'title\', \'Cost: $2.78\');\r\n    $(\"#Mono\").attr(\'title\', \'Cost: $17,10\');\r\n	$(\"#PTINR\").attr(\'title\', \'Cost: $12,07\');\r\n	$(\"#Rubella\").attr(\'title\', \'Cost: $10,00\');\r\n	$(\"#PrenatalAntibody\").attr(\'title\', \'Cost: $10,00\');\r\n	$(\"#RepeatPrenatal\").attr(\'title\', \'Cost: $10,00\');\r\n\r\n\r\n	$(\"#chkMicro_Cervical\").attr(\'title\', \'Cost: $11.09\');\r\n	$(\"#chkMicro_Vaginal\").attr(\'title\', \'Cost: $11.09\');\r\n	$(\"#chkMicro_Chlamydia\").attr(\'title\', \'Cost: $16.46\');\r\n	$(\"#chkMicro_VaginalRectalGroupBStrep\").attr(\'title\', \'Cost: $15.40\');\r\n    $(\"#chkMicro_GC\").attr(\'title\', \'Cost: $28.85 - 11.09\');\r\n\r\n	$(\"#chkMicro_Sputum\").attr(\'title\', \'Cost: $11.09\');\r\n	$(\"#chkMicro_Throat\").attr(\'title\', \'Cost: $3.10\');\r\n	$(\"#chkMicro_Wound\").attr(\'title\', \'Cost: $12.93\');\r\n	$(\"#chkMicro_Other\").attr(\'title\', \'Cost: $12.93\');\r\n\r\n	$(\"#UrineCulture\").attr(\'title\', \'Cost: $10.34 + $9.55/org + $11.55/Ab Sus\');\r\n	$(\"#StoolCS\").attr(\'title\', \'Cost: $17.37 + $14.42/org\');\r\n	$(\"#StoolOP\").attr(\'title\', \'Cost: $9.12\');\r\n\r\n	$(\"#Hepatitis_Acute\").attr(\'title\', \'Cost: $36.12\');\r\n	$(\"#Hepatitis_Chronic\").attr(\'title\', \'Cost: $47.26\');\r\n	$(\"#HepA\").attr(\'title\', \'Cost: $10.25\');\r\n	$(\"#HepB\").attr(\'title\', \'Cost: $10.25\');\r\n	$(\"#HepC\").attr(\'title\', \'Cost: $10.25\');\r\n	$(\"#Hepatitis_ImmuneStatus\").attr(\'title\', \'Cost: $47.26\');\r\n\r\n	$(\"#chkPSA_TotalPSA\").attr(\'title\', \'Cost: $14,35\');\r\n	$(\"#chkPSA_Insured\").attr(\'title\', \'Cost: $14,35 insured if known or suspected prostate cancer\');\r\n	$(\"#chkPSA_Uninsured\").attr(\'title\', \'Cost: $35.00\');\r\n\r\n	$(\"#chkVitaminD_Uninsured\").attr(\'title\', \'Cost: $39.00\');\r\n	$(\"#chkVitaminD_Insured\").attr(\'title\', \'Cost: $11.66 insured for: osteoporosis, rickets, osteopenia, malabsorption syndromes and  renal disease, or for persons who are on medications that affect vitamin D metabolism. \');\r\n\r\n\r\n	\r\n	setInterval(function calculateCost() {\r\n		  $(\'#Costs\').val(0);\r\n		  StartAddIfMissingTitle(\'Costs\',\"\" );\r\n		  \r\n		  var othertests = $(\'#OtherTests\').val();\r\n		  var OtherTests = othertests.toUpperCase(); \r\n		  var match = OtherTests.search(\"AST|PHOSPHATE|PO4|URIC|LDH|LACTATE DEHYDROGENASE\");\r\n\r\n			if ( (match != -1)||(($(\'#Sodium\').val()==\'X\')||($(\'#Potassium\').val()==\'X\')||($(\'#Creatinine\').val()==\'X\')||($(\'#Albumin\').val()==\'X\')||($(\'#ALP\').val()==\'X\')||($(\'#ALT\').val()==\'X\')||($(\'#Bilirubin\').val()==\'X\')||($(\'#GGT\').val()==\'X\')||($(\'#TProtein\').val()==\'X\')||($(\'#Calcium\').val()==\'X\')||($(\'#CreatineKinase\').val()==\'X\')||($(\'#GlucoseRandom\').val()==\'X\')||($(\'#GlucoseFasting\').val()==\'X\') ) ) {\r\n			newcost = Math.round(($(\'#Costs\').val()*1)+15.62);\r\n			$(\'#Costs\').val(newcost);\r\n			AddIfMissingTitle(\'Costs\',\"Base Chemistry Fee: $14.28\\n\" );\r\n			}\r\n		  \r\n			if ($(\'#Sodium\').val()==\'X\') {\r\n			newcost = Math.round(($(\'#Costs\').val()*1)+1.16);\r\n			$(\'#Costs\').val(newcost);\r\n			AddIfMissingTitle(\'Costs\',\"Na: $1.16\\n\" );\r\n			}\r\n			if ($(\'#Potassium\').val()==\'X\') {\r\n			newcost = Math.round(($(\'#Costs\').val()*1)+1.16);\r\n			$(\'#Costs\').val(newcost);\r\n			AddIfMissingTitle(\'Costs\',\"K: $1.16\\n\" );\r\n			}\r\n			if ($(\'#Creatinine\').val()==\'X\') {\r\n			newcost = Math.round(($(\'#Costs\').val()*1)+1.28);\r\n			$(\'#Costs\').val(newcost);\r\n			AddIfMissingTitle(\'Costs\',\"eGFR: $1.28\\n\" );\r\n			} \r\n			if ($(\'#Albumin\').val()==\'X\') {\r\n			newcost = Math.round(($(\'#Costs\').val()*1)+1.55);\r\n			$(\'#Costs\').val(newcost);\r\n			AddIfMissingTitle(\'Costs\',\"Alb: $1.55\\n\" );\r\n			}\r\n			if ($(\'#ALP\').val()==\'X\') {\r\n			newcost = Math.round(($(\'#Costs\').val()*1)+1.57);\r\n			$(\'#Costs\').val(newcost);\r\n			AddIfMissingTitle(\'Costs\',\"ALP: $1.57\\n\" );\r\n			}\r\n			if ($(\'#ALT\').val()==\'X\') {\r\n			newcost = Math.round(($(\'#Costs\').val()*1)+1.28);\r\n			$(\'#Costs\').val(newcost);\r\n			AddIfMissingTitle(\'Costs\',\"ALT: $1.28\\n\" );\r\n			}\r\n			if ($(\'#Bilirubin\').val()==\'X\') {\r\n			newcost = Math.round(($(\'#Costs\').val()*1)+1.55);\r\n			$(\'#Costs\').val